INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ae5948c4-e4d1-4eea-9f00-522fd7fd3131',
  '00000000-0000-0000-0000-000000000001',
  $escape$tRPC vs gRPC — When Protobuf and Native Streaming Beat TypeScript RPC$escape$,
  $escape$tRPC's type safety comes from TypeScript inference — no `.proto` files, no codegen. gRPC flips this: protobuf schemas are the source of truth, generating typed stubs for Go, Rust, Java, and TypeScript alike. That polyglot boundary is gRPC's primary advantage over tRPC.

gRPC defines four streaming modes: unary (equivalent to tRPC queries/mutations), server streaming, client streaming, and bidirectional. tRPC's `.subscription()` approximates server streaming via WebSockets using `observable<T>`, but exposes no API surface for client-streaming or bidirectional flows. If a client needs to push a stream of audio chunks while simultaneously receiving transcription back, gRPC is the only clean fit — tRPC's subscription model simply can't express it.

Protobuf serialization is also 3–10x more compact than tRPC's JSON-over-HTTP payload — material at high message throughput or on constrained networks.

Stick with tRPC when your stack is TypeScript end-to-end and zero-codegen type safety is the priority. Reach for gRPC when you have non-TS consumers, need binary wire efficiency, or require client-streaming and bidirectional patterns that tRPC's `observable` abstraction cannot model.$escape$,
  $escape$// tRPC's closest analog to gRPC server streaming
const appRouter = router({
  stockFeed: publicProcedure
    .input(z.object({ ticker: z.string() }))
    .subscription(({ input }) => {
      return observable<{ price: number; ts: number }>((emit) => {
        const id = setInterval(() => {
          emit.next({ price: getPrice(input.ticker), ts: Date.now() });
        }, 1000);
        return () => clearInterval(id);
      });
    }),
});
// gRPC adds ClientStreaming + BidiStreaming — tRPC has no procedure type for these$escape$,
  $escape$typescript$escape$,
