INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '945ab4d9-d706-49c9-8ead-1ea9fed74ee2',
  '00000000-0000-0000-0000-000000000001',
  $escape$tRPC Pagination — Cursor vs Offset, Total Counts, and Infinite Scroll$escape$,
  $escape$tRPC has no built-in pagination, so the pattern lives entirely in your router input/output schemas. Cursor-based pagination is the right default for feeds: define input with `z.object({ cursor: z.string().nullish(), limit: z.number().min(1).max(100).default(20) })`, return `{ items, nextCursor }` where `nextCursor` is the last item's ID (or null when exhausted). Offset pagination is simpler but breaks under concurrent inserts — reserve it for admin tables where total counts matter. Avoid `SELECT COUNT(*)` on every request; it's expensive. Instead, use a separate `getCount` procedure or return a `hasMore` boolean derived from fetching `limit + 1` items and slicing. On the frontend, use `useInfiniteQuery` from `@tanstack/react-query` with tRPC's `.useInfiniteQuery()` wrapper — pass `getNextPageParam: (lastPage) => lastPage.nextCursor` and it wires cursor forwarding automatically. Flatten pages with `data.pages.flatMap(p => p.items)` for rendering. Avoid mixing cursor logic with `select` transforms, as they run post-fetch and can silently drop the `nextCursor` field.$escape$,
  $escape$// server
export const postRouter = router({
  list: publicProcedure
    .input(z.object({ cursor: z.string().nullish(), limit: z.number().min(1).max(50).default(20) }))
    .query(async ({ input, ctx }) => {
      const items = await ctx.db.post.findMany({
        take: input.limit + 1,
        cursor: input.cursor ? { id: input.cursor } : undefined,
        orderBy: { createdAt: 'desc' },
      });
      const hasMore = items.length > input.limit;
      return { items: hasMore ? items.slice(0, -1) : items, nextCursor: hasMore ? items[items.length - 2].id : null };
    }),
});

// client
const { data, fetchNextPage, hasNextPage } = trpc.post.list.useInfiniteQuery(
  { limit: 20 },
  { getNextPageParam: (lastPage) => lastPage.nextCursor }
);$escape$,
  $escape$typescript$escape$,
