INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f8067853-cb83-4534-b5c7-cda6632a262b',
  '00000000-0000-0000-0000-000000000001',
  $escape$tRPC Idempotency — Safe Queries, Risky Mutations, and Idempotency Keys$escape$,
  $escape$tRPC's `query` procedures are safe and idempotent by design — calling `trpc.user.getById.query(id)` ten times never mutates state and always returns the same result. Mutations are a different story: `trpc.order.create.mutate()` called twice creates two orders.

To make mutations idempotent, embed an `idempotencyKey` field in your Zod input schema. On the server, check a fast store (Redis or a DB unique constraint) before executing side effects. If the key exists, return the cached response. If not, execute and persist.

This matters most with tRPC's TanStack Query integration: failed mutations are retried automatically, and without idempotency guards, a network timeout followed by a retry can double-charge a customer or create duplicate records.

Generate keys client-side with `crypto.randomUUID()` scoped to the operation. Expire them after 24h — that window covers all realistic retry scenarios. Namespace keys by mutation type (`order:create`, `payment:capture`) to prevent cross-operation collisions. The server should treat the key as a content-addressed cache, not a lock.$escape$,
  $escape$// server/routers/orders.ts
export const ordersRouter = router({
  create: t.procedure
    .input(z.object({
      idempotencyKey: z.string().uuid(),
      items: z.array(z.object({ productId: z.string(), qty: z.number() })),
    }))
    .mutation(async ({ input, ctx }) => {
      const cached = await ctx.redis.get(`order:create:${input.idempotencyKey}`);
      if (cached) return JSON.parse(cached);

      const order = await ctx.db.order.create({ data: { items: input.items } });
      await ctx.redis.setex(`order:create:${input.idempotencyKey}`, 86400, JSON.stringify(order));
      return order;
    }),
});$escape$,
  $escape$typescript$escape$,
