INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b2cdab7e-7760-44e1-8032-98fe2838a6a6',
  '00000000-0000-0000-0000-000000000001',
  $escape$tRPC Caching — HTTP Headers, ETags, and CDN-Safe Queries$escape$,
  $escape$tRPC queries default to POST, which CDNs and browsers refuse to cache. Switch to GET by setting `methodOverride: 'GET'` on `httpLink` — queries then hit `GET /api/trpc/users.list?input=...`, a URL CDNs can cache and browsers can revalidate. Add cache semantics server-side via `responseMeta` in your tRPC handler. This callback receives the resolved procedure `type` and `errors` array, letting you conditionally emit headers only for successful queries. For ETag-based conditional requests, hash the serialized response and return it as the `etag` header — clients send `If-None-Match` on repeat requests, enabling 304 short-circuits without re-fetching the database. Key constraint: `httpBatchLink` encodes multiple calls into one URL, breaking CDN cache key isolation. Use `splitLink` to route idempotent queries through `httpLink` with GET and all mutations through `httpBatchLink`. Pair `max-age` with `stale-while-revalidate` for zero-latency reads on stale-tolerant data — the CDN serves the cached byte instantly while revalidating in the background. ETags give you byte-exact freshness; SWR gives you perceived speed.$escape$,
  $escape$import { createHash } from 'crypto';

// server — pass to fetchRequestHandler or createHTTPHandler
responseMeta({ type, errors, data }) {
  if (type !== 'query' || errors.length > 0) return {};
  const body = JSON.stringify(data);
  const etag = `"${createHash('sha1').update(body).digest('hex').slice(0, 16)}"`;
  return {
    headers: {
      'cache-control': 'public, max-age=30, stale-while-revalidate=120',
      etag,
    },
  };
},

// client — opt queries into GET so CDNs can cache by URL
httpLink({ url: '/api/trpc', methodOverride: 'GET' })$escape$,
  $escape$typescript$escape$,
